import React, { useState, useEffect } from 'react';
import { AnalysisJson, AnalyzedPoint, VideoIdea } from '../types';

interface ExtendedAnalyzedPoint extends AnalyzedPoint {
  directConflictIndices: number[]; // Store indices of Original Points this point replaces/overlaps with
}

interface Props {
  analysisText: string;
  selectedIdea: VideoIdea | null; 
  onNext: (selectedPoints: string) => void;
  onBack: () => void;
}

export const Step4Analysis: React.FC<Props> = ({ analysisText, selectedIdea, onNext, onBack }) => {
  const [parsedData, setParsedData] = useState<{
    original: ExtendedAnalyzedPoint[];
    alternative: ExtendedAnalyzedPoint[];
  } | null>(null);

  const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set());
  const [rawView, setRawView] = useState(false);
  const [showContext, setShowContext] = useState(false);

  useEffect(() => {
    try {
      let cleanedText = analysisText.replace(/```json/g, '').replace(/```/g, '').trim();
      const firstBrace = cleanedText.indexOf('{');
      const firstBracket = cleanedText.indexOf('[');
      let json: any;

      if (firstBrace !== -1 && (firstBracket === -1 || firstBrace < firstBracket)) {
          const jsonMatch = cleanedText.match(/\{[\s\S]*\}/);
          if (jsonMatch) json = JSON.parse(jsonMatch[0]);
      } else if (firstBracket !== -1) {
          const jsonMatch = cleanedText.match(/\[[\s\S]*\]/);
          if (jsonMatch) json = { originalPoints: JSON.parse(jsonMatch[0]), alternativePoints: [] };
      }

      if (!json) throw new Error("Could not find valid JSON structure");

      const normalize = (p: any, prefix: string, i: number): ExtendedAnalyzedPoint => {
          const text = (p.overlapExplanation || "");

          // Regex to catch "Poin Awal #3", "Poin Awal # 3", "Poin #3"
          // We look specifically for overlaps with other points in the list
          const conflictIndices: number[] = [];

          // Match "Poin Awal #X" or "Poin #X"
          const matches = [...text.matchAll(/(?:Poin Awal|Poin)\s*#\s*(\d+)/gi)];

          matches.forEach(m => {
            const idx = parseInt(m[1]) - 1; // Convert 1-based to 0-based
            if (idx >= 0) conflictIndices.push(idx);
          });

          return {
              ...p,
              id: `${prefix}-${i}`,
              overlapGroupId: p.overlapGroupId !== undefined ? `${p.overlapGroupId}` : undefined,
              directConflictIndices: conflictIndices
          };
      };

      const rawOriginals = (json.originalPoints || []).map((p: any, i: number) => normalize(p, 'orig', i));
      const rawAlternatives = (json.alternativePoints || []).map((p: any, i: number) => normalize(p, 'alt', i));

      const initialSelection = new Set<string>();
      rawOriginals.forEach((p) => {
        // Only select strong points initially if they don't have heavy conflicts listed first
        if (p.classification === 'Kuat') initialSelection.add(p.id);
      });

      setParsedData({ original: rawOriginals, alternative: rawAlternatives });
      setSelectedIds(initialSelection);
    } catch (e) {
      console.error("Failed to parse analysis JSON", e);
      setRawView(true);
    }
  }, [analysisText]);

  const toggleSelection = (id: string) => {
    if (!parsedData) return;
    const allPoints = [...parsedData.original, ...parsedData.alternative];
    const targetPoint = allPoints.find(p => p.id === id);
    if (!targetPoint) return;

    const newSet = new Set(selectedIds);
    if (!newSet.has(id)) {
        // LOGIC MUTUALLY EXCLUSIVE (Saling Meniadakan)

        // 1. If we are in "Original Points" list
        if (id.startsWith('orig')) {
            const myIndex = parseInt(id.split('-')[1]);

            // A. Check if this point says it overlaps with others (Outgoing conflict)
            targetPoint.directConflictIndices.forEach(conflictIdx => {
                const conflictId = `orig-${conflictIdx}`;
                if (newSet.has(conflictId)) {
                    newSet.delete(conflictId); // Auto-deselect the conflicting point
                }
            });

            // B. Check if OTHER points say they overlap with THIS point (Incoming conflict)
            parsedData.original.forEach((otherP, idx) => {
                if (otherP.directConflictIndices.includes(myIndex)) {
                     if (newSet.has(otherP.id)) {
                        newSet.delete(otherP.id); // Auto-deselect the point that claims conflict with us
                     }
                }
            });
        }

        // 2. Existing logic for Alternatives vs Originals
        if (id.startsWith('alt')) {
            targetPoint.directConflictIndices.forEach(idx => {
                const origPoint = parsedData.original[idx];
                if (origPoint && newSet.has(origPoint.id)) newSet.delete(origPoint.id);
            });
        }

        // 3. Existing logic: If picking original, deselect alternative that consumes it
        if (id.startsWith('orig')) {
            const myIndex = parseInt(id.split('-')[1]);
            parsedData.alternative.forEach(alt => {
                if (alt.directConflictIndices.includes(myIndex)) {
                    if (newSet.has(alt.id)) newSet.delete(alt.id);
                }
            });
        }

        newSet.add(id);
    } else {
        newSet.delete(id);
    }
    setSelectedIds(newSet);
  };

  const handleNext = () => {
    if (!parsedData) return;
    const allPoints = [...parsedData.original, ...parsedData.alternative];
    const sortedSelection = Array.from(selectedIds)
        .map(id => allPoints.find(p => p.id === id))
        .filter(Boolean)
        .sort((a, b) => {
            const getIndex = (strId: string) => parseInt(strId.split('-')[1] || '0');
            if (a!.id.startsWith('orig') && b!.id.startsWith('alt')) return -1;
            if (a!.id.startsWith('alt') && b!.id.startsWith('orig')) return 1;
            return getIndex(a!.id) - getIndex(b!.id);
        });

    const selectedPointsList = sortedSelection
      .map(p => `- ${p!.title} (${p!.classification}): ${p!.details}`);

    onNext(selectedPointsList.join('\n'));
  };

  const formatOverlapText = (text: string) => {
    if (!text) return null;
    // Regex matches "Poin Awal #1" or "Poin Awal #10" case insensitive
    const regex = /((?:Poin\s+Awal|Poin)\s*#\d+)/gi;
    const parts = text.split(regex);
    return parts.map((part, i) => 
      regex.test(part) ? 
        <span key={i} className="bg-yellow-400 text-black px-1.5 py-0.5 rounded-md font-black border border-black mx-1 shadow-[2px_2px_0px_rgba(0,0,0,0.2)] text-[11px] transform -rotate-2 inline-block">{part}</span> : 
        part
    );
  };

  if (rawView || !parsedData) {
    return (
      <div className="space-y-6">
        <textarea className="w-full h-96 p-4 border rounded font-mono text-sm" value={analysisText} readOnly />
        <div className="flex justify-end gap-4">
          <button onClick={onBack} className="bg-white border px-6 py-2 rounded">Kembali</button>
          <button onClick={() => onNext(analysisText)} className="bg-gray-900 text-white px-6 py-2 rounded">Lanjut Manual</button>
        </div>
      </div>
    );
  }

  const renderTable = (points: ExtendedAnalyzedPoint[], title: string, isAlternative: boolean) => (
    <div className="border-0 rounded-2xl shadow-xl bg-white mb-12 flex flex-col max-h-[700px] overflow-hidden">
      <div className={`px-8 py-5 border-b-2 ${isAlternative ? 'bg-emerald-700 border-emerald-800' : 'bg-gray-800 border-gray-900'} text-white flex-shrink-0 sticky top-0 z-20 shadow-lg flex justify-between items-center`}>
        <div className="flex items-center gap-3">
           <div className={`w-3 h-10 ${isAlternative ? 'bg-emerald-400' : 'bg-yellow-400'} rounded-full`}></div>
           <h3 className="font-black text-xl uppercase tracking-[0.1em]">{title}</h3>
        </div>
        <div className="flex gap-4">
            <span className="text-[10px] font-black uppercase tracking-widest opacity-60 bg-white/10 px-3 py-1 rounded-full">{points.length} ITEM</span>
        </div>
      </div>
      <div className="overflow-auto flex-1 w-full scrollbar-thin scrollbar-thumb-gray-300">
        <table className="w-full text-left text-sm border-collapse">
          <thead className="bg-gray-50 border-b-2 sticky top-0 z-10 shadow-sm">
            <tr>
              <th className="px-6 py-4 font-black text-[10px] uppercase tracking-widest text-gray-400 w-24 text-center bg-gray-50">Pilih</th>
              <th className="px-8 py-4 font-black text-[10px] uppercase tracking-widest text-gray-400 w-1/4 min-w-[250px] bg-gray-50">Konten Poin</th>
              <th className="px-8 py-4 font-black text-[10px] uppercase tracking-widest text-gray-400 w-36 bg-gray-50 text-center">Klasifikasi</th>
              <th className="px-8 py-4 font-black text-[10px] uppercase tracking-widest text-gray-400 min-w-[400px] bg-gray-50">Detail & Audit Strategis</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-gray-100">
            {points.map((point, index) => {
               const isSelected = selectedIds.size > 0 && selectedIds.has(point.id);
               // Check internal overlap logic for warning display
               const hasConflict = point.directConflictIndices.length > 0;

               return (
              <tr 
                key={point.id} 
                onClick={() => toggleSelection(point.id)}
                className={`hover:bg-gray-50 cursor-pointer transition-all duration-300 ${
                    isSelected ? 'bg-yellow-50/70 border-l-8 border-l-yellow-500' : 'border-l-8 border-l-transparent'
                }`}
              >
                <td className="px-6 py-6 text-center">
                   <div className="flex justify-center items-center">
                      <input
                        type="checkbox"
                        checked={isSelected}
                        onChange={() => toggleSelection(point.id)}
                        className={`w-8 h-8 cursor-pointer transition-all ${
                             point.overlapGroupId !== undefined ? 'rounded-full' : 'rounded-lg'
                        } ${isSelected ? 'text-yellow-600 ring-4 ring-yellow-500/20 border-yellow-500' : 'text-gray-200 border-gray-300'}`}
                      />
                   </div>
                </td>
                <td className="px-8 py-6 align-top">
                  <div className="flex items-start">
                      <span className="text-[10px] font-black text-white bg-gray-900 px-2 py-1 rounded-md mr-3 mt-1 shadow-sm">#{index + 1}</span>
                      <div className="flex-1">
                          <div className={`font-black text-lg leading-tight tracking-tight transition-colors ${isSelected ? 'text-yellow-900' : 'text-gray-900'}`}>{point.title}</div>
                          {hasConflict && !isSelected && !isAlternative && (
                              <div className="mt-3">
                                  <span className="inline-flex items-center px-2 py-1 rounded-md text-[9px] border uppercase tracking-widest font-black transition-all shadow-sm bg-red-50 text-red-700 border-red-200 ring-1 ring-red-100">
                                      <svg className="w-3 h-3 mr-1" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" /></svg>
                                      ADA IRISAN
                                  </span>
                              </div>
                          )}
                      </div>
                  </div>
                </td>
                <td className="px-8 py-6 align-top text-center">
                  <span className={`px-4 py-1.5 rounded-lg text-[10px] font-black uppercase tracking-[0.15em] inline-block shadow-sm border ${
                    point.classification === 'Kuat' ? 'bg-emerald-100 text-emerald-800 border-emerald-200' :
                    point.classification === 'Sedang' ? 'bg-amber-100 text-amber-800 border-amber-200' :
                    'bg-rose-100 text-rose-800 border-rose-200'
                  }`}>
                    {point.classification}
                  </span>
                </td>
                <td className={`px-8 py-6 align-top leading-relaxed transition-colors ${isSelected ? 'text-gray-900 font-medium' : 'text-gray-700'}`}>
                  <p className="text-base font-medium mb-3">{point.details}</p>
                  {point.overlapExplanation && (
                      <div className={`text-xs p-4 rounded-xl border-l-4 shadow-md transition-all animate-fade-in-up ${isSelected ? 'bg-white border-yellow-500 text-yellow-900' : 'bg-orange-50 border-orange-300 text-orange-900'}`}>
                          <div className="flex items-center gap-2 mb-2">
                             <div className="w-1.5 h-4 bg-orange-400 rounded-full"></div>
                             <span className="font-black uppercase text-[9px] tracking-[0.2em] text-orange-800">Audit Redundansi v6.3:</span> 
                          </div>
                          <div className="leading-relaxed font-semibold italic text-sm">
                            {formatOverlapText(point.overlapExplanation)}
                          </div>
                      </div>
                  )}
                </td>
              </tr>
            )})}
          </tbody>
        </table>
      </div>
    </div>
  );

  return (
    <div className="space-y-10 pb-32">
      <div className="border-b-2 border-gray-100 pb-6">
        <div className="flex justify-between items-end">
            <div>
                <h2 className="text-4xl font-black text-gray-900 tracking-tighter">Analisis & Seleksi Poin <span className="text-yellow-500">v6.3</span></h2>
                <p className="text-gray-500 mt-2 font-medium text-lg">
                Audit strategis dengan <span className="text-gray-800 font-bold">Deteksi Konflik Multi-Poin</span>. Memastikan narasi tidak redundant.
                </p>
            </div>
            <button onClick={() => setShowContext(!showContext)} className="bg-gray-100 hover:bg-gray-200 text-gray-900 px-6 py-3 rounded-2xl font-black uppercase tracking-widest text-[10px] transition-all flex items-center shadow-sm">
                {showContext ? 'Sembunyikan Ide' : 'Lihat Ide Terpilih'}
                <svg className={`w-4 h-4 ml-2 transform transition-transform ${showContext ? 'rotate-180' : ''}`} fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 9l-7 7-7-7" /></svg>
            </button>
        </div>
      </div>

      {showContext && selectedIdea && (
          <div className="bg-gray-900 text-white rounded-[2rem] p-8 shadow-2xl animate-fade-in-up mb-10 overflow-hidden relative border border-white/5">
              <div className="absolute top-0 right-0 p-8 opacity-10">
                  <svg className="w-48 h-48" fill="currentColor" viewBox="0 0 24 24"><path d="M13 10V3L4 14h7v7l9-11h-7z" /></svg>
              </div>
              <div className="relative z-10 grid md:grid-cols-2 gap-10">
                  <div className="space-y-4">
                      <span className="text-[10px] font-black text-yellow-500 uppercase tracking-[0.3em] block">Video Objective</span>
                      <h3 className="text-3xl font-black leading-tight tracking-tight">{selectedIdea.title}</h3>
                      <div className="h-1 w-20 bg-yellow-500 rounded-full"></div>
