                      <span className="text-[10px] font-black text-gray-400 uppercase tracking-[0.3em] block mb-3">Narrative Hook Context</span>
                      <p className="text-lg font-medium leading-relaxed italic text-gray-300">"{selectedIdea.hook}"</p>
                  </div>
              </div>
          </div>
      )}

      <div className="space-y-12">
        {renderTable(parsedData.original, "Audit Poin Awal", false)}
        {renderTable(parsedData.alternative, "Konsolidasi & Alternatif Brutal", true)}
      </div>

      <div className="fixed bottom-0 right-0 left-0 md:left-64 bg-white/80 backdrop-blur-2xl border-t border-gray-100 p-6 shadow-[0_-20px_40px_-15px_rgba(0,0,0,0.1)] z-50 flex flex-col sm:flex-row justify-between items-center px-12">
        <div className="flex items-center gap-6 mb-4 sm:mb-0">
            <div className="flex flex-col items-center">
                <span className="text-[10px] font-black text-gray-400 uppercase tracking-[0.2em] mb-1">Status Seleksi</span>
                <div className="bg-yellow-400 text-black px-6 py-2 rounded-2xl border-2 border-black font-black text-2xl font-mono shadow-xl leading-none">
                    {selectedIds.size}
                </div>
            </div>
            <div className="text-sm text-gray-500 font-bold max-w-[200px] leading-snug">
                Poin yang dipilih akan disusun menjadi Struktur Narasi Final V6.3.
            </div>
        </div>
        <div className="flex gap-4 w-full sm:w-auto">
            <button onClick={onBack} className="bg-white border-2 border-gray-200 text-gray-900 hover:border-gray-900 px-10 py-5 rounded-3xl font-black uppercase tracking-widest text-[10px] transition-all active:scale-95 shadow-lg w-full sm:w-auto">← Kembali</button>
            <button onClick={handleNext} disabled={selectedIds.size === 0} className="bg-gray-900 hover:bg-black text-white px-14 py-5 rounded-3xl font-black uppercase tracking-widest text-[10px] transition-all disabled:opacity-50 disabled:cursor-not-allowed shadow-[0_15px_30px_-5px_rgba(0,0,0,0.3)] hover:shadow-black/40 active:scale-95 w-full sm:w-auto flex items-center justify-center gap-2">
              Lanjut Ke Struktur ({selectedIds.size})
