import React, { useState, useEffect } from 'react';
import { AnalysisJson, AnalyzedPoint, VideoIdea } from '../types';

interface ExtendedAnalyzedPoint extends AnalyzedPoint {
  directConflictIndices: number[]; // Store indices of Original Points this point replaces/overlaps with
}

interface Props {
  analysisText: string;
  selectedIdea: VideoIdea | null; 
  onNext: (selectedPoints: string) => void;
  onBack: () => void;
}

export const Step4Analysis: React.FC<Props> = ({ analysisText, selectedIdea, onNext, onBack }) => {
  const [parsedData, setParsedData] = useState<{
    original: ExtendedAnalyzedPoint[];
    alternative: ExtendedAnalyzedPoint[];
  } | null>(null);

  const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set());
  const [rawView, setRawView] = useState(false);
  const [showContext, setShowContext] = useState(false);

  useEffect(() => {
    try {
      let cleanedText = analysisText.replace(/```json/g, '').replace(/```/g, '').trim();
      const firstBrace = cleanedText.indexOf('{');
      const firstBracket = cleanedText.indexOf('[');
      let json: any;

      if (firstBrace !== -1 && (firstBracket === -1 || firstBrace < firstBracket)) {
          const jsonMatch = cleanedText.match(/\{[\s\S]*\}/);
          if (jsonMatch) json = JSON.parse(jsonMatch[0]);
      } else if (firstBracket !== -1) {
          const jsonMatch = cleanedText.match(/\[[\s\S]*\]/);
          if (jsonMatch) json = { originalPoints: JSON.parse(jsonMatch[0]), alternativePoints: [] };
      }

      if (!json) throw new Error("Could not find valid JSON structure");

      const normalize = (p: any, prefix: string, i: number): ExtendedAnalyzedPoint => {
          const text = (p.overlapExplanation || "");

          // Regex to catch "Poin Awal #3", "Poin Awal # 3", "Poin #3"
          // We look specifically for overlaps with other points in the list
          const conflictIndices: number[] = [];

          // Match "Poin Awal #X" or "Poin #X" - finding ALL occurrences
          const matches = [...text.matchAll(/(?:Poin Awal|Poin)\s*#\s*(\d+)/gi)];

          matches.forEach(m => {
            const idx = parseInt(m[1]) - 1; // Convert 1-based to 0-based
            if (idx >= 0 && !conflictIndices.includes(idx)) {
                conflictIndices.push(idx);
            }
          });

          return {
              ...p,
              id: `${prefix}-${i}`,
              overlapGroupId: p.overlapGroupId !== undefined ? `${p.overlapGroupId}` : undefined,
              directConflictIndices: conflictIndices
          };
      };

      const rawOriginals = (json.originalPoints || []).map((p: any, i: number) => normalize(p, 'orig', i));
      const rawAlternatives = (json.alternativePoints || []).map((p: any, i: number) => normalize(p, 'alt', i));

      const initialSelection = new Set<string>();
      rawOriginals.forEach((p) => {
        // Only select strong points initially if they don't have heavy conflicts listed first
        if (p.classification === 'Kuat') initialSelection.add(p.id);
      });

      setParsedData({ original: rawOriginals, alternative: rawAlternatives });
      setSelectedIds(initialSelection);
    } catch (e) {
      console.error("Failed to parse analysis JSON", e);
      setRawView(true);
    }
  }, [analysisText]);

  const toggleSelection = (id: string) => {
    if (!parsedData) return;
    const allPoints = [...parsedData.original, ...parsedData.alternative];
    const targetPoint = allPoints.find(p => p.id === id);
    if (!targetPoint) return;

    const newSet = new Set(selectedIds);
    if (!newSet.has(id)) {
        // --- LOGIC MUTUALLY EXCLUSIVE (Saling Meniadakan) ---

        // 1. If we are selecting an ORIGINAL Point
        if (id.startsWith('orig')) {
            const myIndex = parseInt(id.split('-')[1]);

            // A. Check internal Original conflicts (existing logic)
            targetPoint.directConflictIndices.forEach(conflictIdx => {
                const conflictId = `orig-${conflictIdx}`;
                if (newSet.has(conflictId)) newSet.delete(conflictId);
            });
            parsedData.original.forEach((otherP) => {
                if (otherP.directConflictIndices.includes(myIndex)) {
                     if (newSet.has(otherP.id)) newSet.delete(otherP.id);
                }
            });

            // B. Deselect any ALTERNATIVE that claims to replace THIS original point
            parsedData.alternative.forEach(alt => {
                if (alt.directConflictIndices.includes(myIndex)) {
                    if (newSet.has(alt.id)) newSet.delete(alt.id);
                }
            });
        }

        // 2. If we are selecting an ALTERNATIVE Point
        if (id.startsWith('alt')) {
            // Deselect ALL Original points that this alternative combines/replaces
            targetPoint.directConflictIndices.forEach(idx => {
                const origPoint = parsedData.original[idx];
                if (origPoint && newSet.has(origPoint.id)) {
                    newSet.delete(origPoint.id);
                }
            });
        }

        newSet.add(id);
    } else {
        newSet.delete(id);
    }
    setSelectedIds(newSet);
  };

  const handleNext = () => {
    if (!parsedData) return;
    const allPoints = [...parsedData.original, ...parsedData.alternative];
    const sortedSelection = Array.from(selectedIds)
        .map(id => allPoints.find(p => p.id === id))
        .filter(Boolean)
        .sort((a, b) => {
            const getIndex = (strId: string) => parseInt(strId.split('-')[1] || '0');
            if (a!.id.startsWith('orig') && b!.id.startsWith('alt')) return -1;
            if (a!.id.startsWith('alt') && b!.id.startsWith('orig')) return 1;
            return getIndex(a!.id) - getIndex(b!.id);
        });

    const selectedPointsList = sortedSelection
      .map(p => `- ${p!.title} (${p!.classification}): ${p!.details}`);

    onNext(selectedPointsList.join('\n'));
  };

  const formatOverlapText = (text: string) => {
    if (!text) return null;
    // Regex matches "Poin Awal #1" or "Poin Awal #10" case insensitive
    const regex = /((?:Poin\s+Awal|Poin)\s*#\d+)/gi;
    const parts = text.split(regex);
    return parts.map((part, i) => 
      regex.test(part) ? 
        <span key={i} className="bg-yellow-400 text-black px-1.5 py-0.5 rounded-md font-black border border-black mx-1 shadow-[2px_2px_0px_rgba(0,0,0,0.2)] text-[11px] transform -rotate-2 inline-block">{part}</span> : 
        part
    );
  };

  if (rawView || !parsedData) {
    return (
      <div className="space-y-6">
        <textarea className="w-full h-96 p-4 border rounded font-mono text-sm" value={analysisText} readOnly />
        <div className="flex justify-end gap-4">
          <button onClick={onBack} className="bg-white border px-6 py-2 rounded">Kembali</button>
          <button onClick={() => onNext(analysisText)} className="bg-gray-900 text-white px-6 py-2 rounded">Lanjut Manual</button>
        </div>
      </div>
    );
  }

