  return generateContent(PROMPT_FINAL_STRUCTURE, prompt, "gemini-3-pro-preview");
};

export const generateScriptSection = async (finalStructure: string, sectionName: string, targetWordCount: number, totalPoints: number) => {
  let extraInstructions = "";
  const lowerSection = sectionName.toUpperCase();
  const introTarget = Math.round(targetWordCount * 0.12);
  const outroTarget = Math.round(targetWordCount * 0.08);
  const bodyTotal = targetWordCount - introTarget - outroTarget;
  const bodyPerPoint = Math.max(100, Math.round(bodyTotal / (totalPoints || 5)));

  if (lowerSection.includes("HOOK") || lowerSection.includes("BABAK 1")) {
      extraInstructions += `\n\nTARGET PANJANG: Sekitar ${introTarget} Kata.

      [ATURAN KHUSUS BABAK 1 (V6.6) - CLEAN FLOW]:
      1. FORMAT OUTPUT: Langsung tulis kalimat naskah (Narasi only).
      2. DILARANG menulis header apapun seperti "BABAK 1", "HOOK", "SEGMEN A", "SEGMEN B", atau "(Total Word Count)".
      3. HINDARI intro meta seperti "Berikut adalah naskah...". Langsung masuk ke Hook 1.

      [STRUKTUR MENTAL (JANGAN DITULIS LABELNYA)]:
         - Kalimat 1-2: Context Lean (Konfirmasi 'Kamu').
         - Kalimat 3-4: Scroll Stop (Bantahan Keras/Interjection).
         - Kalimat 5-6: High Stakes (Curiosity Loop).
         - Kalimat 7-8: Roadmap (Janji Video).

      [STYLE]: Staccato. Cepat. Tanpa Basa-basi "Halo guys".`;

  } else if (lowerSection.includes("PENUTUP") || lowerSection.includes("BABAK 3")) {
      extraInstructions += `\n\nTARGET PANJANG: Sekitar ${outroTarget} Kata.

      [ATURAN V6.6]: 
      1. FORMAT OUTPUT: Langsung kalimat penutup.
      2. DILARANG menulis header "BABAK 3", "PENUTUP", atau "KESIMPULAN".
      3. Akhiri dengan 'Ciao'.
      4. Fokus pada CTA emosional (Spirit perlawanan/Perubahan nasib).`;

  } else {
      extraInstructions += `\n\nTARGET PANJANG: Sekitar ${bodyPerPoint} Kata untuk poin ini.`;
      const match = sectionName.match(/([a-zA-Z\s]+)\s*#(\d+)/);
      if (match) {
         const currentNumber = parseInt(match[2]);

         extraInstructions += `\n\nATURAN KHUSUS (STRICT V6.6):`;
         extraInstructions += `\n1. START FORMAT: Mulai paragraf LANGSUNG dengan kalimat pembahasan/inti masalah.`;
         extraInstructions += `\n2. DILARANG KERAS menulis "Nomor ${currentNumber}", "Poin ${currentNumber}", atau angka urutan apapun di awal paragraf.`;
         extraInstructions += `\n3. DILARANG MENULIS ULANG JUDUL SUB-BAB. JANGAN sebutkan nama poinnya lagi.`;
         extraInstructions += `\n   - SALAH: "Nomor ${currentNumber}. Gaji lu itu..."`;
         extraInstructions += `\n   - BENAR: "Lu sadar gak sih kalau gaji lu itu..."`;
         extraInstructions += `\n4. NO INTRO: Dilarang basa-basi. Langsung ke inti masalah.`;
         extraInstructions += `\n5. NO REHOOK/TEASER: DILARANG membuat kalimat 'teaser' untuk poin berikutnya di akhir paragraf. Cukup selesaikan poin ini dengan solusi.`;
         extraInstructions += `\n6. INTEGRATED SOLUTION: Solusi harus ada di paragraf terakhir bagian ini.`;
      }
  }

  const prompt = `Struktur Narasi Final:\n${finalStructure}\n\nPERINTAH: Tuliskan Naskah Penuh (Full Text) untuk bagian: ${sectionName}. ${extraInstructions}`;
  const response = await generateContent(PROMPT_SCRIPT_ROLE, prompt, "gemini-3-pro-preview");
  return cleanScriptResponse(response);
};

