   - **Split Style**: Tentukan mana text "EMPHASIS" (Putih di box Merah) dan "NORMAL" (Hitam + Shadow).
   - **Prompt**: Deskripsikan adegan visual yang DRAMATIS dan SIMPLE.
`;

export const generateTitleAndThumbnailPairs = async (
  context: string,
  keywords: string,
  count: number = 3
): Promise<TitleThumbnailPair[]> => {
  const ai = getAIClient();

  const schema: Schema = {
    type: Type.OBJECT,
    properties: {
      pairs: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
             title: { type: Type.STRING, description: "Judul Video (TANPA ANGKA LISTICLE)" },
             thumbnail_prompt: { type: Type.STRING, description: "Prompt visual untuk AI image generator" },
             text_overlay: { type: Type.STRING, description: "Teks pendek di dalam gambar" },
             emphasis_word: { type: Type.STRING, description: "Kata yang ditaruh di box merah" },
             normal_word: { type: Type.STRING, description: "Sisa kata (hitam)" },
             feasibility_score: { type: Type.NUMBER, description: "Skor prediksi CTR 1-100" }
          },
          required: ["title", "thumbnail_prompt", "text_overlay", "emphasis_word", "normal_word"]
        }
      }
    },
    required: ["pairs"]
  };

  const userPrompt = `
    Buatlah ${count} variasi Judul Video + Konsep Thumbnail berdasarkan naskah/konteks berikut:

    KONTEKS:
    ${context.substring(0, 2000)}...

    KEYWORDS WAJIB: ${keywords}

    SYARAT MUTLAK:
    1. JUDUL HARUS "STORY-DRIVEN" atau "MYSTERY". DILARANG Format "X Hal", "X Cara", "X Tips".
    2. Setiap Judul harus punya konsep Thumbnail yang unik.
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.0-flash", // Menggunakan model cepat
      contents: userPrompt,
      config: {
        systemInstruction: THUMBNAIL_SYSTEM_INSTRUCTION,
        responseMimeType: "application/json",
        responseSchema: schema,
      },
    });

    const json = JSON.parse(response.text || "{}");

    return json.pairs.map((p: any, idx: number) => ({
        id: `pair-${Date.now()}-${idx}`,
        title: p.title,
        thumbnail: {
            prompt: p.thumbnail_prompt,
            suggestedText: p.text_overlay,
            emphasisText: p.emphasis_word,
            normalText: p.normal_word,
            status: 'idle',
            feasibilityScore: p.feasibility_score || 85
        }
    }));
  } catch (e) {
      console.error(e);
      throw new Error("Gagal generate Title/Thumbnail pairs");
  }
};

