              pair.thumbnail.prompt,
              refImages,
              bgImage,
              pair.thumbnail.emphasisText,
              pair.thumbnail.normalText
          );

          setPairs(prev => prev.map(p => p.id === pairId ? { 
              ...p, 
              thumbnail: { ...p.thumbnail, status: 'success', imageUrl } 
          } : p));

      } catch (e) {
          setPairs(prev => prev.map(p => p.id === pairId ? { ...p, thumbnail: { ...p.thumbnail, status: 'error' } } : p));
      }
  };

  const handleRefImageChange = (e: React.ChangeEvent<HTMLInputElement>) => {
      if (e.target.files) setRefImages(Array.from(e.target.files));
