// --- SCRIPT GENERATION PATCHED (No Headers, No Subtitles) ---
export const generateScriptSection = async (finalStructure: string, sectionName: string, targetWordCount: number, totalPoints: number) => {
  let extraInstructions = "";
  const lowerSection = sectionName.toUpperCase();
  const introTarget = Math.round(targetWordCount * 0.12);
  const outroTarget = Math.round(targetWordCount * 0.08);
  const bodyTotal = targetWordCount - introTarget - outroTarget;
  const bodyPerPoint = Math.max(100, Math.round(bodyTotal / (totalPoints || 5)));

  if (lowerSection.includes("HOOK") || lowerSection.includes("BABAK 1")) {
      extraInstructions += `\n\nTARGET PANJANG: Sekitar ${introTarget} Kata.
      [ATURAN KHUSUS BABAK 1 (V6.6)]:
      1. FORMAT OUTPUT: Langsung tulis kalimat naskah (Narasi only).
      2. DILARANG menulis header apapun atau intro meta.
      3. Style: Staccato, Cepat, Tanpa Basa-basi.`;
  } else if (lowerSection.includes("PENUTUP") || lowerSection.includes("BABAK 3")) {
      extraInstructions += `\n\nTARGET PANJANG: Sekitar ${outroTarget} Kata.
      [ATURAN V6.6]: 
      1. FORMAT OUTPUT: Langsung kalimat penutup.
      2. DILARANG menulis header "BABAK 3", "PENUTUP".
      3. Akhiri dengan 'Ciao'.`;
  } else {
      extraInstructions += `\n\nTARGET PANJANG: Sekitar ${bodyPerPoint} Kata.`;
      const match = sectionName.match(/([a-zA-Z\s]+)\s*#(\d+)/); // Match "BABAK 2 #1"

      // Patch Logic to remove "BABAK 2:" prefix if present for title extraction
      const rawTitle = sectionName.replace(/BABAK 2:?\s*/i, '').trim();

      extraInstructions += `\n\nATURAN KHUSUS (STRICT V6.6 - DIRECT DIVE):`;
      extraInstructions += `\n1. START LANGSUNG KE ISI: Mulai paragraf pertama LANGSUNG dengan pembahasan materi. `;
      extraInstructions += `\n2. DILARANG KERAS MENGULANG JUDUL POIN SEBAGAI INTRO.`;
      extraInstructions += `\n   - SALAH: "${rawTitle}. Ya, poin ini membahas..."`;
      extraInstructions += `\n   - SALAH: "Oke lanjut ke poin berikutnya yaitu ${rawTitle}..."`;
      extraInstructions += `\n   - BENAR: "Lu sadar gak sih kalau masalah ini tuh bikin..." (Langsung serang)`;
      extraInstructions += `\n3. DILARANG MENULIS HEADER/JUDUL POIN. Hanya narasi.`;
      extraInstructions += `\n4. SOLUSI PRAKTIS harus ada di akhir bagian ini.`;
  }

  const prompt = `Struktur Narasi Final:\n${finalStructure}\n\nPERINTAH: Tuliskan Naskah Penuh (Full Text) untuk bagian: "${sectionName}". ${extraInstructions}`;
  const response = await generateContent(PROMPT_SCRIPT_ROLE, prompt, "gemini-3-pro-preview");
  return cleanScriptResponse(response);
};

export const generateDescription = async (fullScript: string, videoTitle: string) => {
