const THUMBNAIL_SYSTEM_INSTRUCTION = `
### PERAN & TUJUAN
Anda adalah Art Director & Copywriter YouTube Top 1% Global.
Tugas: Membuat pasangan JUDUL KLIKBATE dan KONSEP THUMBNAIL visual untuk split testing.

### ATURAN UTAMA:
1. **JUDUL (STRICT)**:
   - DILARANG ADA ANGKA LISTICLE (Contoh: "5 Alasan", "7 Fakta" -> DILARANG).
   - Gunakan psikologi: Curiosity Gap, Fear of Missing Out, Kontroversi.
   - Panjang: 5-12 Kata.
   - Bahasa: Indonesia Baku tapi Menampar.

2. **KONSEP THUMBNAIL (VISUAL)**:
   - **Text Overlay**: Harus singkat (2-4 kata). JANGAN ulangi judul. Harus melengkapi.
   - **Visual**: Deskripsikan karakter "ILMU LIDI" (Stickman Hitam) dalam situasi dramatis.
`;

export const generateTitleAndThumbnailPairs = async (context: string, keywords: string, count: number = 3): Promise<TitleThumbnailPair[]> => {
  const ai = getAIClient();
  const schema: Schema = {
    type: Type.OBJECT,
    properties: {
      pairs: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
             title: { type: Type.STRING },
             thumbnail_prompt: { type: Type.STRING },
             text_overlay: { type: Type.STRING },
             emphasis_word: { type: Type.STRING },
             normal_word: { type: Type.STRING },
             feasibility_score: { type: Type.NUMBER }
          },
          required: ["title", "thumbnail_prompt", "text_overlay", "emphasis_word", "normal_word"]
        }
      }
    },
    required: ["pairs"]
  };

  const userPrompt = `Buatlah ${count} variasi Judul Video + Konsep Thumbnail (Ada Karakter Ilmu Lidi). Konteks:\n${context.substring(0, 2000)}...\nKeywords: ${keywords}`;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.0-flash",
      contents: userPrompt,
      config: {
        systemInstruction: THUMBNAIL_SYSTEM_INSTRUCTION,
        responseMimeType: "application/json",
        responseSchema: schema,
      },
    });
    const json = JSON.parse(response.text || "{}");
    return json.pairs.map((p: any, idx: number) => ({
        id: `pair-${Date.now()}-${idx}`,
        title: p.title,
        thumbnail: {
            prompt: p.thumbnail_prompt,
            suggestedText: p.text_overlay,
            emphasisText: p.emphasis_word,
            normalText: p.normal_word,
            status: 'idle',
            feasibilityScore: p.feasibility_score || 85
        }
    }));
  } catch (e) {
      console.error(e);
      throw new Error("Gagal generate Title/Thumbnail pairs");
  }
};

// --- IMAGE GENERATION SERVICE PATCHED (Support "Ilmu Lidi" & Real Image) ---

export const generateRealThumbnailImage = async (
  prompt: string,
  referenceImages: File[],
  referenceBackground: File | null,
  referenceTextStyle: File | null, // NEW PARAMETER
  emphasisText: string,
  normalText: string
): Promise<string> => {
  const ai = getAIClient();
  const parts: any[] = [];

  // 1. System Prompt Enforcing "Ilmu Lidi" Style
  const engineeredPrompt = `
    ROLE: Professional YouTube Thumbnail Artist.

    [MANDATORY CHARACTER STYLE - "ILMU LIDI"]:
    - SUBJECT: A minimalistic BLACK STICK FIGURE ("Stickman").
    - FEATURES: Round black head, large expressive white eyes (no pupils), simple line body, arms, and legs.
    - HANDS: White palms (mitten style or simple circles).
    - MOOD: High contrast, dramatic lighting, intense expression.
    - DO NOT render realistic humans. DO NOT render 3D cartoons. STICKMAN ONLY.

    [SCENE DESCRIPTION]:
    ${prompt}

    [TEXT LAYOUT GUIDANCE]:
    - There will be text overlay added later: "${emphasisText} ${normalText}"
    - Leave negative space at the TOP or CENTER for text.
    - Avoid cluttering the bottom-right corner.
  `;
  parts.push({ text: engineeredPrompt });

  // 2. Background
  if (referenceBackground) {
    const bgBase64 = await fileToBase64(referenceBackground);
    parts.push({ text: "USE THIS BACKGROUND COMPOSITION:" });
    parts.push({ inlineData: { data: bgBase64, mimeType: referenceBackground.type } });
  }

  // 3. Characters (Stickman Poses)
  if (referenceImages && referenceImages.length > 0) {
      parts.push({ text: "REFERENCE POSE/EXPRESSION (Convert to Stickman):" });
      for (const file of referenceImages) {
        const base64 = await fileToBase64(file);
        parts.push({ inlineData: { data: base64, mimeType: file.type } });
      }
  }

  // 4. Text Style Reference (NEW)
  if (referenceTextStyle) {
      const textBase64 = await fileToBase64(referenceTextStyle);
      parts.push({ text: "REFERENCE TEXT TYPOGRAPHY/COLOR STYLE:" });
      parts.push({ inlineData: { data: textBase64, mimeType: referenceTextStyle.type } });
  }

  try {
    // Menggunakan model imagen-3 jika tersedia di API key user, atau gemini-2.0-flash experimental
    // Note: Pastikan API Key support model 'imagen-3.0-generate-001' atau sejenisnya
    const response = await ai.models.generateContent({
      model: "gemini-2.0-flash", // Atau ganti ke 'imagen-3.0-generate-001' jika punya akses
      contents: { parts },
    });

    // Handle Image Response (Logic untuk mengambil gambar dari response Gemini)
    // Jika model mengembalikan blob/image:
    if (response.candidates && response.candidates[0].content.parts) {
         for (const part of response.candidates[0].content.parts) {
             if (part.inlineData && part.inlineData.data) {
                 return `data:${part.inlineData.mimeType};base64,${part.inlineData.data}`;
             }
         }
    }

    // Fallback if text response contains URL (jarang terjadi di Gemini API standar)
    return "https://via.placeholder.com/1280x720/000000/FFFFFF?text=Error+No+Image+Data+Returned";

  } catch (error) {
     console.error("Image Gen Error:", error);
     // Fallback Mockup agar user tidak frustrasi total saat develop
     return "https://via.placeholder.com/1280x720/000000/FFFFFF?text=API+Error+Check+Console";
  }
};

