import React, { useState, useEffect, useRef } from 'react';
import { ScriptSection } from '../types';

interface Props {
  finalStructure: string;
  finalSubtitles: string[];
  videoTitle: string;
  onGenerateSection: (sectionName: string) => Promise<string>;
  onBack: () => void;
  onNext: (sections: ScriptSection[]) => void;
}

export const Step8Script: React.FC<Props> = ({ finalStructure, finalSubtitles, videoTitle, onGenerateSection, onBack, onNext }) => {
  const [sections, setSections] = useState<ScriptSection[]>([]);
  const [currentStepIndex, setCurrentStepIndex] = useState(0);
  const [isProcessing, setIsProcessing] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [copied, setCopied] = useState(false);
  const hasStartedRef = useRef(false);

  // Construct the queue dynamically based on subtitles
  const partsQueue = [
    "BABAK 1: HOOK",
    ...finalSubtitles.map((sub) => `BABAK 2: ${sub}`),
    "BABAK 3: PENUTUP"
  ];

  // Helper to remove markdown bold/italic syntax client-side
  const cleanContent = (text: string) => {
    if (!text) return '';
    // Remove ** and * used for markdown bold/italic
    return text.replace(/\*\*/g, '').replace(/\*/g, '').trim();
  };

  // Automated Sequential Generation
  useEffect(() => {
    if (hasStartedRef.current) return;
    hasStartedRef.current = true;
    processQueue(0);
  }, []);

  const processQueue = async (startIndex: number) => {
    setIsProcessing(true);
    setError(null);

    for (let i = startIndex; i < partsQueue.length; i++) {
        setCurrentStepIndex(i);
        const partName = partsQueue[i];

        try {
            const rawContent = await onGenerateSection(partName);
            const content = cleanContent(rawContent); // Apply cleaning
            setSections(prev => [...prev, { title: partName, content }]);

            // Wait a bit before next request to be safe (and for UX)
            await new Promise(r => setTimeout(r, 1000));
        } catch (e) {
            console.error(`Failed to generate ${partName}`, e);
            setError(`Gagal membuat bagian: ${partName}`);
            setIsProcessing(false);
            return; // Stop the loop on error
        }
    }

    setIsProcessing(false);
  };

  const handleRetry = () => {
      processQueue(currentStepIndex);
  };

  const handleDownloadSection = (title: string, content: string) => {
    const element = document.createElement("a");
    const file = new Blob([content], {type: 'text/plain'});
    element.href = URL.createObjectURL(file);
    // Sanitize title for filename
    const safeTitle = title.replace(/[^a-z0-9]/gi, '_').toLowerCase();
    element.download = `${safeTitle}.txt`;
    document.body.appendChild(element); // Required for this to work in FireFox
    element.click();
    document.body.removeChild(element);
  };

  const getFullScriptText = () => {
      const header = `JUDUL VIDEO: ${videoTitle}\n\n`;
      const body = sections.map(s => `=== ${s.title} ===\n\n${s.content}`).join('\n\n');
      return header + body;
  };

  const copyAll = () => {
    const fullText = getFullScriptText();
    navigator.clipboard.writeText(fullText);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const handleDownloadAll = () => {
    const fullText = getFullScriptText();
    const element = document.createElement("a");
    const file = new Blob([fullText], {type: 'text/plain'});
    element.href = URL.createObjectURL(file);

    // Sanitize video title for filename
    const safeFilename = videoTitle.replace(/[^a-z0-9 ]/gi, '').trim().replace(/\s+/g, '_') || 'Naskah_Video';
    element.download = `${safeFilename}.txt`;

    document.body.appendChild(element);
    element.click();
    document.body.removeChild(element);
  };

  const progressPercentage = Math.round((sections.length / partsQueue.length) * 100);

  return (
    <div className="flex flex-col h-full space-y-6 pb-24">
       <div className="border-b-2 border-gray-100 pb-4 flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div className="flex items-center gap-4">
             <button 
                onClick={onBack}
                className="p-3 hover:bg-gray-100 rounded-2xl transition-all border border-transparent hover:border-gray-200"
