  const [targetWordCount, setTargetWordCount] = useState<number>(1600);
  const [isReading, setIsReading] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const readFileAsText = (file: File): Promise<string> => {
      return new Promise((resolve, reject) => {
          const reader = new FileReader();
          reader.onload = () => resolve(reader.result as string);
          reader.onerror = reject;
          reader.readAsText(file);
      });
  };

  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
      const files = Array.from(e.target.files);
      if (files.length + fileNames.length > 10) {
        alert("Maksimal 10 file.");
        return;
      }

      setIsReading(true);
      try {
        const newFileNames: string[] = [];
        const newFileContents: string[] = [];

        for (const file of files) {
            newFileNames.push(file.name);
            const textContent = await readFileAsText(file);
            newFileContents.push(textContent);
        }
        setFileNames(prev => [...prev, ...newFileNames]);
        setFileContents(prev => [...prev, ...newFileContents]);
      } catch (err) {
          alert("Gagal membaca file.");
      } finally {
          setIsReading(false);
      }
