                value={text}
                onChange={(e) => setText(e.target.value)}
            />
        </div>

        <div className="grid md:grid-cols-2 gap-8">
            <div>
                <label className="block text-sm font-bold text-gray-900 mb-2 uppercase tracking-wide">
