import * as GeminiService from './services/geminiService';

const initialState: AppState = {
  step: AppStep.INPUT_REFERENCE,
  referenceText: '',
  fileContents: [],
  keywords: '',
  targetWordCount: 1600,
  selectedIdea: null,
  analysis: '',
  selectedPoints: [],
  optimizedStructure: '',
  titleOptions: '',
  finalTitle: '',
  finalSubtitles: [],
  finalStructure: '',
  script: [],
  finalDescription: '',
  finalTags: '',
  isLoading: false,
  error: null,
};

const playNotificationSound = () => {
  try {
    const AudioContext = window.AudioContext || (window as any).webkitAudioContext;
    if (!AudioContext) return;

    const ctx = new AudioContext();
    const osc = ctx.createOscillator();
    const gain = ctx.createGain();

    osc.connect(gain);
    gain.connect(ctx.destination);

    osc.type = 'sine';
    osc.frequency.setValueAtTime(523.25, ctx.currentTime);
    osc.frequency.exponentialRampToValueAtTime(1046.5, ctx.currentTime + 0.1);

    gain.gain.setValueAtTime(0.8, ctx.currentTime);
    gain.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + 0.5);

    osc.start(ctx.currentTime);
    osc.stop(ctx.currentTime + 0.5);
  } catch (e) {
    console.error("Audio play failed", e);
  }
};

const App: React.FC = () => {
  const [state, setState] = useState<AppState>(initialState);
  const prevLoadingRef = useRef(state.isLoading);

  useEffect(() => {
    if (prevLoadingRef.current && !state.isLoading && !state.error) {
      playNotificationSound();
    }
    prevLoadingRef.current = state.isLoading;
  }, [state.isLoading, state.error]);

  const handleError = (error: any) => {
    setState(prev => ({ ...prev, isLoading: false, error: error.message || "Terjadi kesalahan API." }));
    alert("Terjadi kesalahan: " + (error.message || "Unknown error"));
  };

  const handleSaveState = () => {
    try {
        const json = JSON.stringify(state, null, 2);
        const blob = new Blob([json], { type: 'application/json' });
        const href = URL.createObjectURL(blob);
        const link = document.createElement('a');
        link.href = href;
        const dateStr = new Date().toISOString().slice(0, 10);
        link.download = `IlmuLidi_Session_${dateStr}.json`;
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
    } catch (e) {
        alert("Gagal menyimpan progress.");
        console.error(e);
    }
  };

  const handleLoadState = (file: File) => {
      const reader = new FileReader();
      reader.onload = (e) => {
          try {
              const text = e.target?.result as string;
              if (!text) return;
              const loadedState = JSON.parse(text) as AppState;
              if (loadedState.step === undefined || loadedState.referenceText === undefined) {
                  throw new Error("Invalid session file format.");
              }
              setState(loadedState);
              alert("Progress berhasil dimuat! Anda kembali ke Step " + ((loadedState.step || 0) + 1));
          } catch (err) {
              alert("Gagal memuat file: Format tidak sesuai.");
              console.error(err);
          }
      };
      reader.readAsText(file);
  };

  const handleBack = () => {
    setState(prev => {
        if (prev.step === AppStep.FINAL_STRUCTURE) {
             return { ...prev, step: AppStep.OPTIMIZE_ORDER };
        }
        if (prev.step > AppStep.INPUT_REFERENCE) {
            // Logic to skip steps if in shortcut mode?
            // For now, standard back works, but if from shortcut (TitleThumb), back goes to Input
            if (prev.step === AppStep.TITLE_AND_THUMBNAIL && prev.script.length === 0) {
                 return { ...prev, step: AppStep.INPUT_REFERENCE };
            }
            return { ...prev, step: prev.step - 1 };
        }
        return prev;
    });
  };

  const handleReferenceSubmit = async (text: string, files: string[], keywords: string, wordCount: number) => {
    setState(prev => ({ 
        ...prev, 
        isLoading: true, 
        referenceText: text, 
        fileContents: files, 
        keywords: keywords, 
        targetWordCount: wordCount, 
        error: null 
    }));
    try {
      const ideasText = await GeminiService.generateIdeas(text, files, keywords);
      setState(prev => ({ ...prev, step: AppStep.SELECT_IDEA, analysis: ideasText, isLoading: false }));
    } catch (e) {
      handleError(e);
    }
  };

  // NEW: Shortcut Handler
  const handleVariantsOnly = (text: string, files: string[], keywords: string) => {
     setState(prev => ({ 
        ...prev, 
        referenceText: text, 
        fileContents: files, 
        keywords: keywords, 
        script: [], // Empty script indicates shortcut mode
        step: AppStep.TITLE_AND_THUMBNAIL
    }));
  };

  const handleRegenerateIdeas = async () => {
    setState(prev => ({ ...prev, isLoading: true, error: null }));
    try {
        const ideasText = await GeminiService.generateIdeas(state.referenceText, state.fileContents, state.keywords || '');
        setState(prev => ({ ...prev, analysis: ideasText, isLoading: false }));
    } catch (e) {
        handleError(e);
    }
  };

  const handleIdeaSelect = async (idea: VideoIdea) => {
    setState(prev => ({ ...prev, isLoading: true, selectedIdea: idea, error: null }));
    try {
      const analysisJson = await GeminiService.analyzeIdea(idea); 
      setState(prev => ({ ...prev, step: AppStep.ANALYZE_POINTS, analysis: analysisJson, isLoading: false }));
    } catch (e) {
      handleError(e);
    }
  };

  const handlePointsSelection = async (points: string) => {
     if (!state.selectedIdea) return;
     const pointsArray = points.split('\n').filter(line => line.trim().length > 0);
     setState(prev => ({ ...prev, isLoading: true, error: null, selectedPoints: pointsArray }));
     try {
         const optimizedStr = await GeminiService.generateStructureFromPoints(state.selectedIdea, points, state.targetWordCount);
         setState(prev => ({ ...prev, step: AppStep.OPTIMIZE_ORDER, optimizedStructure: optimizedStr, isLoading: false }));
     } catch (e) {
         handleError(e);
     }
  };

  const handleOptimizedConfirm = async () => {
      const workingTitle = state.selectedIdea?.title || "Draft Title";

      const workingSubtitles = state.selectedPoints.map(p => {
          let clean = p.replace(/^-\s*/, '').trim();
          clean = clean.split('(')[0].trim();
          if (clean.includes(':')) {
             clean = clean.split(':')[0].trim();
          }
          return clean;
      });

      setState(prev => ({ 
          ...prev, 
          isLoading: true, 
          finalTitle: workingTitle,
          finalSubtitles: workingSubtitles,
          error: null 
      }));

      try {
          const finalStr = await GeminiService.generateFinalStructure(state.optimizedStructure, workingTitle, workingSubtitles);
          setState(prev => ({ 
              ...prev, 
              step: AppStep.FINAL_STRUCTURE, 
              finalStructure: finalStr, 
              isLoading: false 
          }));
      } catch (e) {
          handleError(e);
      }
  };

  const handleFinalStructureConfirm = () => {
      setState(prev => ({ ...prev, step: AppStep.SCRIPT_GENERATION }));
  };

  const generateScriptSection = async (sectionName: string) => {
      return GeminiService.generateScriptSection(
          state.finalStructure, 
          sectionName, 
          state.targetWordCount || 1600, 
          state.finalSubtitles.length
      );
  };

  const handleScriptCompleted = (sections: ScriptSection[]) => {
      setState(prev => ({ ...prev, script: sections, step: AppStep.TITLE_AND_THUMBNAIL }));
  };

  const handleTitleThumbCompleted = (pair: TitleThumbnailPair) => {
      setState(prev => ({ 
          ...prev, 
          finalTitle: pair.title, 
          step: AppStep.DESCRIPTION_TAGS 
      }));
  };

  const handleGenerateMetadata = async () => {
    setState(prev => ({ ...prev, isLoading: true, error: null }));
    try {
        // If shortcut mode (no script), use reference text as basis for metadata
        const contentContext = state.script.length > 0 
            ? state.script.map(s => `=== ${s.title} ===\n${s.content}`).join('\n\n')
            : state.referenceText + "\n\n" + state.fileContents.join('\n');

        const [desc, tags] = await Promise.all([
            GeminiService.generateDescription(contentContext, state.finalTitle),
            GeminiService.generateTags(contentContext, state.finalTitle)
        ]);

        setState(prev => ({ 
            ...prev, 
            finalDescription: desc, 
            finalTags: tags, 
            isLoading: false 
        }));
    } catch (e) {
        handleError(e);
    }
  };

  return (
    <Layout 
        currentStep={state.step} 
        isLoading={state.isLoading}
        onSaveState={handleSaveState}
        onLoadState={handleLoadState}
    >
      {state.step === AppStep.INPUT_REFERENCE && (
        <Step1Input 
            onNext={handleReferenceSubmit} 
            onGenerateVariantsOnly={handleVariantsOnly} // Pass new handler
        />
      )}

      {state.step === AppStep.SELECT_IDEA && (
        <Step2Ideas 
            ideasText={state.analysis} 
            onNext={handleIdeaSelect} 
            onBack={handleBack}
            onRegenerate={handleRegenerateIdeas}
        />
      )}

      {state.step === AppStep.ANALYZE_POINTS && (
        <Step4Analysis 
            analysisText={state.analysis}
            selectedIdea={state.selectedIdea}
            onNext={handlePointsSelection} 
            onBack={handleBack}
        />
      )}

      {state.step === AppStep.OPTIMIZE_ORDER && (
          <div className="space-y-6 flex flex-col h-full pb-24">
              <div className="border-b pb-4">
                  <h2 className="text-2xl font-bold text-gray-900">Struktur Narasi</h2>
                  <p className="text-gray-600 mt-1">AI telah menyusun poin-poin Anda menjadi kerangka narasi.</p>
              </div>
              <div className="flex-1 overflow-auto bg-gray-50 p-6 rounded border whitespace-pre-wrap text-sm font-mono">
                  {state.optimizedStructure}
              </div>

              <div className="fixed bottom-0 right-0 left-0 md:left-64 bg-white/90 backdrop-blur-md border-t border-gray-200 p-4 shadow-[0_-4px_6px_-1px_rgba(0,0,0,0.1)] z-50 flex justify-center items-center gap-4">
                  <button onClick={handleBack} className="bg-white border border-gray-300 text-gray-700 hover:bg-gray-50 px-6 py-3 rounded-lg font-medium transition-all shadow-sm">← Kembali</button>
                  <button onClick={handleOptimizedConfirm} className="bg-gray-900 hover:bg-black text-white px-8 py-3 rounded-lg font-medium transition-all shadow-md">Lanjut: Finalisasi Struktur</button>
              </div>
          </div>
      )}

      {state.step === AppStep.FINAL_STRUCTURE && (
          <div className="space-y-6 flex flex-col h-full pb-24">
              <div className="border-b pb-4">
                  <h2 className="text-2xl font-bold text-gray-900">Finalisasi Struktur</h2>
                  <p className="text-gray-600 mt-1">Struktur final untuk naskah.</p>
              </div>
              <div className="flex-1 overflow-auto bg-gray-50 p-6 rounded border whitespace-pre-wrap text-sm font-mono leading-relaxed">
                  {state.finalStructure}
              </div>
              <div className="fixed bottom-0 right-0 left-0 md:left-64 bg-white/90 backdrop-blur-md border-t border-gray-200 p-4 shadow-[0_-4px_6px_-1px_rgba(0,0,0,0.1)] z-50 flex justify-center items-center gap-4">
                  <button onClick={handleBack} className="bg-white border border-gray-300 text-gray-700 hover:bg-gray-50 px-6 py-3 rounded-lg font-medium transition-all shadow-sm">← Kembali</button>
                  <button onClick={handleFinalStructureConfirm} className="bg-gray-900 hover:bg-black text-white px-8 py-3 rounded-lg font-medium transition-all shadow-md">Mulai Generate Naskah</button>
              </div>
          </div>
      )}

      {state.step === AppStep.SCRIPT_GENERATION && (
        <Step8Script 
            finalStructure={state.finalStructure}
            finalSubtitles={state.finalSubtitles}
            videoTitle={state.finalTitle}
            onGenerateSection={generateScriptSection}
            onBack={handleBack}
            onNext={handleScriptCompleted}
        />
      )}

      {state.step === AppStep.TITLE_AND_THUMBNAIL && (
          <Step8TitleThumbnail 
             scriptSections={state.script}
             keywords={state.keywords || ''}
             // Fallback context for shortcut mode
             contextOverride={state.script.length === 0 ? (state.referenceText + "\\n" + state.fileContents.join(' ')) : undefined}
             onNext={handleTitleThumbCompleted}
             onBack={handleBack}
             onGeneratePairs={GeminiService.generateTitleAndThumbnailPairs}
             onGenerateImage={GeminiService.generateRealThumbnailImage}
          />
      )}

      {state.step === AppStep.DESCRIPTION_TAGS && (
        <Step9Metadata 
            description={state.finalDescription || ''}
            tags={state.finalTags || ''}
            onGenerate={handleGenerateMetadata}
            onBack={handleBack}
            isLoading={state.isLoading}
        />
      )}
    </Layout>
  );
};

export default App;

