      <div className="bg-white p-8 rounded-3xl shadow-sm border border-gray-100 space-y-6">
        <div>
            <label className="block text-sm font-bold text-gray-900 mb-2 uppercase tracking-wide">
                1. Text / Link Referensi Utama
            </label>
            <textarea
                className="w-full h-40 p-4 border border-gray-200 rounded-2xl focus:ring-4 focus:ring-yellow-500/20 focus:border-yellow-500 transition-all font-mono text-sm resize-none shadow-inner"
                placeholder="Paste artikel, transkrip, atau catatan kasar di sini..."
                value={text}
                onChange={(e) => setText(e.target.value)}
            />
        </div>

        <div className="grid md:grid-cols-2 gap-8">
            <div>
                <label className="block text-sm font-bold text-gray-900 mb-2 uppercase tracking-wide">
                    2. Upload File Pendukung (.txt, .md, .json)
                </label>
                <div 
                    onClick={() => fileInputRef.current?.click()}
                    className="border-2 border-dashed border-gray-300 rounded-2xl p-6 text-center cursor-pointer hover:border-yellow-500 hover:bg-yellow-50 transition-all group"
                >
                    <input 
                        type="file" 
                        multiple 
                        accept=".txt,.md,.json,.csv" 
                        ref={fileInputRef} 
                        className="hidden" 
                        onChange={handleFileChange}
                    />
                    <div className="text-gray-400 group-hover:text-yellow-600 transition-colors">
                        {isReading ? (
                            <span>Membaca file...</span>
                        ) : fileNames.length > 0 ? (
                            <div className="text-left">
                                <span className="font-bold text-black block mb-2">{fileNames.length} File Terupload:</span>
                                <ul className="list-disc list-inside text-xs font-mono">
                                    {fileNames.map((n, i) => <li key={i} className="truncate">{n}</li>)}
