// Update: Add mandatoryKeywords param
export const generateTitleAndThumbnailPairs = async (
    context: string, 
    keywords: string, 
    mandatoryKeywords: string = '', 
    count: number = 3
): Promise<TitleThumbnailPair[]> => {
  const ai = getAIClient();
  const schema: Schema = {
    type: Type.OBJECT,
    properties: {
      pairs: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
             title: { type: Type.STRING },
             thumbnail_prompt: { type: Type.STRING },
             text_overlay: { type: Type.STRING },
             emphasis_word: { type: Type.STRING },
             normal_word: { type: Type.STRING },
             feasibility_score: { type: Type.NUMBER }
          },
          required: ["title", "thumbnail_prompt", "text_overlay", "emphasis_word", "normal_word"]
        }
      }
    },
    required: ["pairs"]
  };

  let keywordInstruction = "";
  if (mandatoryKeywords && mandatoryKeywords.trim() !== '') {
      keywordInstruction = `\n\n[SYARAT MUTLAK]: Judul WAJIB mengandung kata-kata ini secara verbatim: "${mandatoryKeywords}". Jika tidak ada, Anda GAGAL.`;
  }

  const userPrompt = `Buatlah ${count} variasi Judul Video + Konsep Thumbnail. Konteks:\n${context.substring(0, 2000)}...\n\nKeywords Umum: ${keywords}${keywordInstruction}`;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.0-flash",
      contents: userPrompt,
      config: {
        systemInstruction: THUMBNAIL_SYSTEM_INSTRUCTION,
        responseMimeType: "application/json",
        responseSchema: schema,
      },
    });
    const json = JSON.parse(response.text || "{}");
    return json.pairs.map((p: any, idx: number) => ({
        id: `pair-${Date.now()}-${idx}`,
        title: p.title,
        thumbnail: {
            prompt: p.thumbnail_prompt,
            suggestedText: p.text_overlay,
            emphasisText: p.emphasis_word,
            normalText: p.normal_word,
            status: 'idle',
            feasibilityScore: p.feasibility_score || 85
        }
    }));
  } catch (e) {
      console.error(e);
      throw new Error("Gagal generate Title/Thumbnail pairs");
  }
};

// --- IMAGE GENERATION SERVICE PATCHED (RESTORE STICKMAN) ---

const THUMBNAIL_STYLE_SUFFIX = "Modern 2D webcomic style, bold clean line art, stylized character design, flat colors with cel-shading, cinematic dramatic lighting, volumetric atmosphere, rim lighting, deep shadows, ambient occlusion, depth of field, sharp focus on subject, 8k resolution, high quality digital illustration.";

export const generateRealThumbnailImage = async (
  prompt: string,
  referenceImages: File[],
  referenceBackground: File | null,
  referenceTextStyle: File | null,
  emphasisText: string,
  normalText: string
): Promise<string> => {
  const ai = getAIClient();
  const parts: any[] = [];

  // 1. System Prompt Enforcing "Ilmu Lidi" Mascot (Stickman)
  const engineeredPrompt = `
    ROLE: Professional YouTube Thumbnail Artist.

    [SUBJECT - MANDATORY MASCOT]:
    - **"ILMU LIDI" CHARACTER**: A premium, high-fidelity 2D BLACK STICK FIGURE.
    - **FEATURES**: Perfectly round black head, large expressive WHITE EYES (no pupils), simple line body.
    - **HANDS**: White mitten-like palms.
    - **AESTHETIC**: Not a doodle. Professional vector-like "Stickman" art.

    [VISUAL STYLE]:
    ${THUMBNAIL_STYLE_SUFFIX}

    [SCENE ACTION]:
    ${prompt}

    [TEXT LAYOUT PREPARATION]:
    - Composition must allow space for text: "${emphasisText}" (Red Box) and "${normalText}".
  `;
  parts.push({ text: engineeredPrompt });

  // 2. Background
  if (referenceBackground) {
    const bgBase64 = await fileToBase64(referenceBackground);
    parts.push({ text: "USE THIS BACKGROUND COMPOSITION:" });
    parts.push({ inlineData: { data: bgBase64, mimeType: referenceBackground.type } });
  }

  // 3. Characters
  if (referenceImages && referenceImages.length > 0) {
      parts.push({ text: "REFERENCE CHARACTER (CONVERT TO STICKMAN STYLE):" });
      for (const file of referenceImages) {
        const base64 = await fileToBase64(file);
        parts.push({ inlineData: { data: base64, mimeType: file.type } });
      }
  }

  // 4. Text Style
  if (referenceTextStyle) {
      const textBase64 = await fileToBase64(referenceTextStyle);
      parts.push({ text: "REFERENCE TEXT STYLE:" });
      parts.push({ inlineData: { data: textBase64, mimeType: referenceTextStyle.type } });
  }

  try {
    // Generate Image using Gemini 2.0 Flash
    const response = await ai.models.generateContent({
      model: "gemini-2.0-flash", 
      contents: { parts },
      config: {
          // @ts-ignore
          imageGenerationConfig: {
              aspectRatio: "16:9",
              sampleCount: 1
          }
      }
    });

    // ROBUST RESPONSE PARSING
    if (response.candidates && response.candidates.length > 0) {
        const candidate = response.candidates[0];
        if (candidate.content && candidate.content.parts) {
             for (const part of candidate.content.parts) {
                 // Check for inlineData (Standard Image Response)
                 if (part.inlineData && part.inlineData.data) {
                     return `data:${part.inlineData.mimeType || 'image/png'};base64,${part.inlineData.data}`;
                 }
                 // Check if executableCode or other types exist (rare for image gen but possible)
             }
        }
    }

    console.error("No image data found in response", response);
    throw new Error("No image data returned from API");

  } catch (error) {
     console.error("Image Gen Error:", error);
     // Fallback Placeholder so user sees something failed visually
     return "https://via.placeholder.com/1280x720/FF0000/FFFFFF?text=GENERATION+FAILED+CHECK+CONSOLE";
  }
};

import React, { useState, useRef } from 'react';
import { TitleThumbnailPair, ScriptSection } from '../types';

interface Props {
  scriptSections: ScriptSection[];
  keywords: string;
  contextOverride?: string;
  onNext: (selectedPair: TitleThumbnailPair) => void;
  onBack: () => void;
  onGeneratePairs: (context: string, keywords: string, mandatoryKeywords: string) => Promise<TitleThumbnailPair[]>;
  onGenerateImage: (prompt: string, refs: File[], bg: File | null, txtRef: File | null, emp: string, norm: string) => Promise<string>;
}

export const Step8TitleThumbnail: React.FC<Props> = ({ 
    scriptSections, 
    keywords: initialKeywords, 
    contextOverride,
    onNext, 
    onBack,
    onGeneratePairs,
    onGenerateImage
}) => {
  const [pairs, setPairs] = useState<TitleThumbnailPair[]>([]);
  const [isGeneratingPairs, setIsGeneratingPairs] = useState(false);
  const [mandatoryKeywords, setMandatoryKeywords] = useState(''); // NEW STATE

  // Image Assets Inputs
  const [refImages, setRefImages] = useState<File[]>([]);
  const [bgImage, setBgImage] = useState<File | null>(null);
  const [textStyleImage, setTextStyleImage] = useState<File | null>(null);

  const bgInputRef = useRef<HTMLInputElement>(null);
  const charInputRef = useRef<HTMLInputElement>(null);
  const textInputRef = useRef<HTMLInputElement>(null);

  const [selectedPairId, setSelectedPairId] = useState<string | null>(null);

  const getContext = () => {
      if (contextOverride) return contextOverride;
      return scriptSections.map(s => s.content).join(' ').substring(0, 3000);
  };

  const handleGeneratePairs = async () => {
      setIsGeneratingPairs(true);
      try {
          const context = getContext();
          // Pass mandatoryKeywords to service
          const results = await onGeneratePairs(context, initialKeywords, mandatoryKeywords);
          setPairs(results);
          if (results.length > 0) setSelectedPairId(results[0].id);
      } catch (e) {
          alert("Gagal membuat variasi judul/thumbnail.");
      } finally {
          setIsGeneratingPairs(false);
      }
  };

  const handleGenerateThumbnailImage = async (pairId: string) => {
      const pair = pairs.find(p => p.id === pairId);
      if (!pair) return;

      if (!bgImage) {
          alert("WAJIB Upload Background Referensi dulu!");
          return;
      }

      setPairs(prev => prev.map(p => p.id === pairId ? { ...p, thumbnail: { ...p.thumbnail, status: 'generating' } } : p));

      try {
          const imageUrl = await onGenerateImage(
              pair.thumbnail.prompt,
              refImages,
              bgImage,
              textStyleImage,
              pair.thumbnail.emphasisText,
              pair.thumbnail.normalText
          );

          setPairs(prev => prev.map(p => p.id === pairId ? { 
              ...p, 
              thumbnail: { ...p.thumbnail, status: 'success', imageUrl } 
          } : p));

      } catch (e) {
          console.error(e);
          setPairs(prev => prev.map(p => p.id === pairId ? { 
              ...p, 
              thumbnail: { ...p.thumbnail, status: 'error' } 
          } : p));
          alert("Gagal generate gambar. Cek koneksi atau API Key.");
      }
  };

  const handleRefImageChange = (e: React.ChangeEvent<HTMLInputElement>) => {
      if (e.target.files) setRefImages(Array.from(e.target.files));
  };

  return (
    <div className="space-y-8 pb-32">
      <div className="border-b pb-6 flex justify-between items-end">
        <div>
            <h2 className="text-3xl font-black text-gray-900 tracking-tight">Judul & Visual Split Testing <span className="text-yellow-500">v7.1</span></h2>
            <p className="text-gray-500 mt-2 font-medium">
                Sistem akan membuat 3 Variasi untuk ditest. <span className="text-red-600 font-bold bg-red-50 px-2 py-0.5 rounded">NO LISTICLE / ANGKA.</span>
            </p>
        </div>
        {pairs.length > 0 && (
            <button 
                onClick={handleGeneratePairs} 
                disabled={isGeneratingPairs}
                className="text-xs font-bold text-gray-500 underline hover:text-black"
            >
                {isGeneratingPairs ? 'Regenerating...' : 'Regenerate All Ideas'}
            </button>
        )}
      </div>

      {/* 1. INPUT ASSETS SECTION */}
      <div className="bg-white p-6 rounded-2xl border border-gray-200 shadow-sm space-y-6">
          <div className="flex flex-col md:flex-row gap-6 justify-between items-start md:items-center border-b pb-4 mb-4">
               <div>
                   <h3 className="font-bold text-gray-800 uppercase tracking-wide text-sm">1. Konfigurasi Visual & Judul</h3>
                   <span className="text-xs text-gray-400">Upload aset dan tentukan kata kunci wajib</span>
               </div>
          </div>

          {/* Keyword Wajib Input */}
          <div className="bg-yellow-50 border border-yellow-200 p-4 rounded-xl mb-6">
              <label className="block text-xs font-bold text-gray-700 uppercase mb-2">
                  Kata Kunci Wajib (Harus ada di Judul)
              </label>
              <input 
                  type="text" 
                  value={mandatoryKeywords}
                  onChange={(e) => setMandatoryKeywords(e.target.value)}
                  placeholder="Contoh: Korupsi, DPR, Gaji UMR (Pisahkan dengan koma)"
                  className="w-full p-3 border border-yellow-300 rounded-lg focus:ring-2 focus:ring-yellow-500 outline-none text-sm font-bold text-gray-900 placeholder-gray-400"
              />
              <p className="text-[10px] text-gray-500 mt-1">*Jika kosong, AI akan menentukan sendiri.</p>
          </div>

          <div className="grid md:grid-cols-3 gap-6">
              {/* Background Input */}
              <div>
                  <label className="block text-xs font-bold text-gray-500 uppercase mb-2">1. Background (Wajib)</label>
                  <div 
                    onClick={() => bgInputRef.current?.click()}
                    className={`border-2 border-dashed rounded-xl p-6 text-center cursor-pointer transition-all ${bgImage ? 'border-green-400 bg-green-50' : 'border-gray-300 hover:border-yellow-400 hover:bg-yellow-50'}`}
                  >
                      <input ref={bgInputRef} type="file" accept="image/*" className="hidden" onChange={(e) => e.target.files && setBgImage(e.target.files[0])} />
                      {bgImage ? (
                          <div className="text-green-700 font-bold text-xs truncate">{bgImage.name}</div>
